css:
/* --- 简约冬雪 --- */
/* --- 作者@Rose_are_roses --- */
/* --- 仅免费发布于本人自己的小群，偶尔发布于Discord堆堆demo社区，严禁除以上渠道外的任何获取方式，严禁二传、任何商业行为，仅限社区内二改。 --- */

/* ========== 字体 ========== */
@import url("https://fontsapi.zeoseven.com/36/main/result.css");
body, .text_pole, select, .text_input, textarea, .menu_button, button {
    font-family: var(--font-main) !important;
    font-weight: normal !important;
}
.fa, .fas, .far, .fab, .fa-solid {
    font-family: "Font Awesome 6 Free" !important;
}


/* ========== 全局设置 ========== */
:root {
    --snow-white: #F0FCFF !important;
    --border-blue: #A8D8EA !important;
    --star-blue: #B3D4E7 !important;
    --font-main: "TW-Kai", normal;
}

* {
    text-shadow: none !important;
    box-shadow: none !important;
    filter: none !important;
}


/* ======== 弹窗、侧边栏、菜单 ======== */
.drawer-content,
#table_drawer_content {
  background-color: #FFFFFF !important;
}

/* 侧栏内条目（正则/脚本） */
.regex-script-label.flex-container,
.script-item {
  background: rgb(255, 255, 255);
}

/* 正则调整 */
#saved_regex_scripts, #saved_scoped_scripts { padding-right: 45px; }

/* 侧边栏直角，感谢serein老师的分享 */
.drawer-content {
border-radius: 0;
}

/* 菜单背景填满屏幕，NAKARI老师分享的代码 */
.drawer-content.openDrawer {
        max-height: calc(100dvh - var(--topBarBlockSize));
}
#left-nav-panel,
#right-nav-panel {
    height: 100dvh;
    max-height: 100dvh;
}
@media (max-width: 600px) {
    #right-nav-panel {
        max-height: calc(100dvh - var(--topBarBlockSize));
    }
}


/* ========== 预设页 ========== */
/* 预设条目 */
#completion_prompt_manager .completion_prompt_manager_prompt {
    background-color: rgb(255, 255, 255) !important; 
    border: 1px solid #FFF !important;   
    border-radius: 5px !important;
    margin: 2px 0 !important;     /* 条目之间的垂直间距 */
    padding: 5px 20px !important; /* 条目内部的边距 */
}
/* 悬停效果 */
#completion_prompt_manager .completion_prompt_manager_prompt:hover {
    background-color: rgb(255, 255, 255) !important; 
    border-color: #1A1A1A !important;
    transform: translateY(-1px);
}

/* 预设底板背景 */
#completion_prompt_manager_list {
    background: #FFF !important;
    border: 1px solid #8F8F8F !important;
    border-radius: 10px !important;
    padding: 10px !important;
    margin-top: 15px !important;
}

/* 提示词未启用时的文字颜色，感谢serein老师的分享 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name,
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
color: #7A7A7A;
}
/* 提示词启用时文字颜色 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt:not(.completion_prompt_manager_prompt_disabled) .completion_prompt_manager_prompt_name,
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt:not(.completion_prompt_manager_prompt_disabled) .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
color: #000;
}

/* 提示词标题 */
.completion_prompt_manager_header {
  color: #1A1A1A !important;
}

/* 预设条目中的所有操作按钮颜色 */
.completion_prompt_manager_prompt .fa-toggle-on,
.completion_prompt_manager_prompt .fa-toggle-off,
.completion_prompt_manager_prompt .fa-pencil {
    color: #7D7D7D !important; 
}


/* ========== 顶栏 ========== */
#top-settings-holder {
    background-color: #FFF; 
}
#top-settings-holder .drawer-toggle .drawer-icon {
    background: #FFF !important;
    font-size: 1.55em !important; 
    display: inline-flex;
    align-items: center;
    justify-content: center;
}


/* ======== 底栏 ======== */
#send_form {
background: rgb(255, 255, 255);
border-radius: 8px !important;
border: 1.5px solid #C0C0C0 !important;
padding: 0px;
}

#sheld {
  min-height: 
    calc(100dvh - var(--topBarBlockSize)); 
}

#send_textarea {
  background-color: rgb(255, 255, 255) !important;
  border: 1px solid rgb(255, 255, 255) !important;
  border-radius: 10px !important;
  color: #C0C0C0 !important;
  resize: none !important; 
  margin-top: 7px !important;
}

/* 输入框提示文字 */
#send_textarea::placeholder {
color: transparent;
opacity: 0;
}
#nonQRFormItems {
position: relative !important;
}
#nonQRFormItems::after {
content: "✩⁺𝐇𝐚𝐩𝐩𝐢𝐧𝐞𝐬𝐬 𝐃𝐢𝐚𝐫𝐲·⁺.";
position: absolute;
top: 50%;
left: 50%;
transform: translate(-50%, -50%);
color: #C0C0C0 !important;
font-size: 0.6em;
pointer-events: none;
white-space: nowrap;
z-index: 1;
}
#send_textarea:not(:placeholder-shown) ~ * #nonQRFormItems::after,
#nonQRFormItems:has(#send_textarea:not(:placeholder-shown))::after {
display: none;
}

#options_button::before,
#extensionsMenuButton::before,
#quick-reply-rocket-button i::before,
#send_but::before,
#mes_stop i::before {
    color: #C0C0C0 !important; 
}

/* 隐藏QR，感谢十二老师的分享 */
.qr--buttons {
  opacity: 0;
  visibility: hidden;
  max-height: 0;
  transform: translateY(20px);
  pointer-events: none;
  transition: opacity 0.3s ease-in-out, visibility 0.3s ease-in-out, max-height 0.5s ease, transform 0.5s ease;
}
#send_form:focus-within .qr--buttons {
  opacity: 1;
  visibility: visible;
  max-height: 100px; 
  transform: translateY(0);
  pointer-events: auto;
}


/* ===== 标题框 ===== */
h4,
h4.standoutHeader,
.inline-drawer-header.standoutHeader,
.inline-drawer-toggle.inline-drawer-header,
.extension_container > .inline-drawer > .inline-drawer-toggle.inline-drawer-header,
#kobold_api-presets .title_restorable,
#novel_api-presets .title_restorable,
#openai_api-presets .title_restorable,
#textgenerationwebui_api-presets .title_restorable {
    background: #FFF !important;
    border: 1px solid #8F8F8F !important;
    border-radius: 5px !important;
    color: #666666 !important;
    padding: 5px 15px !important;
    margin-top: 10px !important;
    display: flex;
    align-items: center;
    font-weight: 800;
}

/* --- 移除 API 响应页面标题的样式 --- */
.drawer-content:has(#main_api) h4,
.drawer-content:has(#main_api) .standoutHeader,
.drawer-content:has(#main_api) .inline-drawer-header {
    background: none !important;
    border: none !important;
    border-radius: 0 !important;
    margin-top: 0px !important;
    padding: 5px 0 !important; 
    font-weight: bold !important;     /* 保留加粗 */
}


/* ======== 滚动条 ======== */
/* 完全隐藏滚动条 */
::-webkit-scrollbar {
display: none;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(150, 170, 150, 0.7);
}


/* ======== 收藏栏 ======== */
.hotswap.avatars_inline {
  background: rgb(255, 255, 255);
  border-radius: 10px;
}
/* 收藏角色横向滚动 */
#HotSwapWrapper {
overflow-x: auto; 
}
#HotSwapWrapper::-webkit-scrollbar {
display: none;
}
.hotswap.avatars_inline {
min-width: max-content; 
}
.hotswap.avatars_inline > .avatar.inline_avatar {
display: inline-block;
}
#HotSwapWrapper * {
max-width: none;
}
/* 收藏角色头像描边 */
.character_select.is_fav .avatar {
  outline-color: #1A1A1A !important;
}
/* 收藏角色名字 */
.character_select.is_fav .ch_name {
  color: #000 !important;
}


/* ==========表单控件 ========== */
/* 所有文本输入框、下拉菜单、多行文本框的背景颜色 */
select,
input:not([type="checkbox"]):not([type="radio"]):not([type="range"]),
  textarea:not(#send_textarea) {
  background-color: rgb(255, 255, 255) !important;
  border-radius: 5px;
  border: 1px solid #8F8F8F !important;
}

/* ========== 滑块 + 数字输入框 ========== */
input[type="range"] {
    -webkit-appearance: none !important;
    height: 1px !important;
    appearance: none;
    background: transparent; /* 防止系统灰轨覆盖 */
    filter: none !important;
    width: 100%; /* 根据需要调整滑块长度 */
    margin: 20px 0;
}

/* 轨道样式 */
input[type="range"]::-webkit-slider-runnable-track {
    height: 4px;
    border-radius: 1px;
    border: none;
    background: #666666 !important;
    box-shadow: inset 0 0 4px rgba(180, 200, 220, 0.5);
}

/* 滑块样式 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    box-shadow: none !important;
    width: 24px;
    height: 24px;
    background: url('https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEF8KBpDzcaL2slD-_Miy01Zozcu4I_lQAC0kAAAqr0eVQVMyzoj3dq3TYE.png') no-repeat center / contain;
    border: none;
    border-radius: 50%;
    cursor: pointer;
    margin-top: -10px;
    z-index: 3;
}

/* 数字输入框 */
input[type="number"] {
  background-color: #FFF !important;
  color: #8F8F8F !important;
  border-radius: 5px !important;
}

/* ========== 复选框 ========== */
input[type="checkbox"] {
  -webkit-appearance: none;
  border-radius: 4px;
  background-color: #fff;
  border: 1px solid #8F8F8F;
  cursor: pointer;
  position: relative;
}
input[type="checkbox"]:checked {
  background-color: #999999;
  border-color: #8F8F8F;
}


/* ========== 通知吐司 ========== */
/* 成功通知 */
.toast-success {
    background-color: #666666 !important;
    box-shadow: none !important; 
}
/* 错误通知 */
.toast-error {
    background-color: #C0C0C0 !important;
    border: 1px solid #A0A0A0 !important;
    box-shadow: none !important; 
}
/* 信息通知 */
.toast-info {
    background-color: #d1ecf1 !important;
    box-shadow: none !important; 
}
/* 警告通知 */
.toast-warning {
    background-color: #C0C0C0 !important;
    border: 1px solid #A0A0A0 !important;
    box-shadow: none !important; 
}

/* 消息文字样式 */
.toast-title {
    color: #FFF;
    font-size: 20px;
}
.toast-message {
    color: #FFF !important ;
    font-size: 12px !important ;
}


/* ==========聊天界面 ========== */
.mes {
    display: flex;
    flex-direction: column;
    position: relative;
    padding-top: 10px; 
    background-color: #FFF !important;
    border-radius: 12px !important;
    margin-top: 10px;   /* 控制与上一条的距离 */
    margin-bottom: 10px; /* 控制与下一条的距离 */
}

.mes .mesIDDisplay,
.mes .mes_timer,
.mes .tokenCounterDisplay {
    position: absolute;
    top: 55px;    
    font-size: 11px;
    color: #C0C0C0;
    opacity: 0.8;
}

.mes .tokenCounterDisplay {
    left: 85px; 
}
.mes .mes_timer {
    left: 145px;
}
.mes .mesIDDisplay {
    left: 200px;
}

.mes .mesAvatarWrapper {
}

/* 姓名和时间戳的容器 */
.mes .ch_name {
    position: absolute;
    top: 25px;    /* 距离气泡顶部的距离 */
    left: 85px;   /* 距离气泡左侧的距离 */
    display: flex;
    align-items: baseline;
    gap: 10px;
    margin: 0;
    padding: 0;
}

/* 姓名样式 */
.mes .name_text {
    font-size: 1em;
    font-weight: bold;
    color: #666666; 
}
/* 时间戳样式 */
.mes .timestamp {
    font-size: 0.8em;
    color: #888; 
}

/* 聊天正文 */
.mes .mes_block {
    background: none;
    border: none;
    padding: 0 10px;
    margin: 0;
    margin-bottom: 10px; 
    transform: none !important;
}

/* 正文样式 */
.mes .mes_text {
    padding: 0;
    margin: 0 auto;
    text-align: justify;
}

/* 隐藏空信息 */
.mes .mes_timer:empty,
.mes .mesIDDisplay:empty,
.mes .tokenCounterDisplay:empty {
    display: none;
}
/* 调整最后一条消息与底栏的间距 */
.last_mes {
    margin-bottom: 30px !important; 
}

/* 引用文本 */
.mes q {
    background: linear-gradient(to top, 
        rgba(232, 232, 232) 0%,
        rgba(232, 232, 232) 80%,
        transparent 80%
    );
    padding: 0 0.2em;
    margin: 0 -0.2em;
    color: #000000 !important;
    quotes: none;
}

/* 头像容器 */
.mes .avatar {
    margin-top: 10px;
    pointer-events: none;
    position: relative !important;
    overflow: visible !important;
}
/* 修复最后一条消息顶部的巨大空白 */
.last_mes .mesAvatarWrapper {
    padding-bottom: 0 !important;
}
/* 选中删除消息背景色 */
.mes.selected {
    background-color: rgba(220, 242, 250, 0.5) !important;
    border-radius: 20px !important;
    transition: background-color 0.2s ease-in-out;
}

/* 编辑按钮 */
.mes .mes_buttons {
    position: absolute; 
    top: 25px;
    right: -85px;
    color: #888;
    z-index: 4;
}


/* ========== 头像框 ========== */
.mes .avatar {
    position: relative;
    overflow: visible !important;
}
.mes .avatar::after {
    content: '';
    position: absolute;
    width: 60px;
    height: 60px;
    top: 42%;
    left: 50%;
    transform: translate(-50%, -50%);
    background-image: url('https://files.catbox.moe/b3k36c.gif');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    z-index: 2;
    pointer-events: none;
}


/* ======== 思维链 ======== */
.mes_reasoning_header {
  background-color: #F0F0F0;
  border: 1px solid #F0F0F0;
  border-radius: 50px;
  padding: 5px 12px;
  display: inline-block;  
  margin: 20px 0 0 0px;
  text-align: center;
  align-self: flex-start;   
}
/* 只隐藏非标题的内容 */
.mes_reasoning_header > *:not(.mes_reasoning_header_title) {
  display: none;
}
/* 标题元素样式 */
.mes_reasoning_header_title {
  display: flex !important;
  justify-content: center;
  align-items: center;
  font-family: var(--font-main);
  color: #7D7D7D;
  font-size: 0 !important; /* 隐藏原文字 */
  width: 100%;
  text-align: center;
}
.mes_reasoning_header_title::before {
  content: "·⁺₊♡𝐶𝑎𝑡 𝑝𝑜𝑡𝑖𝑜𝑛♡₊⁺·";
  font-size: 13px;
  font-weight: normal !important;
  color: #7D7D7D;
  line-height: 1.4;
}
.mes_reasoning {
    background: rgba(255, 255, 255, 0.3);
    color: #7A7A7A;
    border-left: 3px solid #E6E6E6;
    position: relative;
    max-height: 300px; 
    overflow-y: auto;
    text-align: left;
}


/* ======== 代码块 ======== */
.mes pre {
    background-color: rgb(255, 255, 255) !important;
    border-radius: 8px;
    padding: 10px;
    overflow-x: auto;
    border: 1.5px solid #C0C0C0; 
}
.mes pre code {
    color: #7A7A7A !important;
    background: none !important;   
    font-size: 0.9em;
}


/* ==========其他美化 ========== */
/* 自定义选中文本 */
::selection {
  background-color: #D3D3D3 !important;
  color: #000000 !important;
  text-shadow: 1px 1px 2px rgba(255,255,255,0.2);
}

/* 世界信息 */
#WorldInfo, 
#wiTopBlock .inline-drawer-content {
    background-color: rgb(255, 255, 255) !important;
    padding: 5px; /* 内边距 */
}

/* 隐藏br（换行符）标签造成的多余空行，来自十二老师的分享 */
.mes_text br + br,
.mes_text br + br + br {
    display: none !important;
}
/* 保持第一个br的正常功能，但隐藏连续的多个br */
.mes_text br:not(:last-child) {
    margin-bottom: 0 !important;
}
/* 确保消息文本容器的顶部没有多余空间 */
.mes_text {
    padding-top: 15px !important;
    margin-top: 10px !important;
}

/* 小图标 */
#right-nav-panel .menu_button.fa-skull,.menu_button.fa-trash-can {
    background-color: #FFF !important; 
}

/* 加载动画 */
#preloader {
    position: fixed;
    margin: 0;
    padding: 0;
    top: 0;
    left: 0;
    z-index: 999999;
    width: 100vw;
    height: 100vh;
    background-image: url(https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEFz75pDqydoZjWYvD16TcVubztDfUaZQACoR4AAqr0eVQWK4KmEekIHzYE.jpg);
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    opacity: 1;
}
#load-spinner {
    --spinner-size: 50px; 
    transition: all var(--animation-duration-2x) ease-out;
    opacity: 1;
    top: calc(50% - var(--spinner-size) / 2);
    left: calc(50% - var(--spinner-size) / 2);
    position: absolute;
    width: var(--spinner-size);
    height: var(--spinner-size);
    background-image: url(https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEF8KBpDzcaL2slD-_Miy01Zozcu4I_lQAC0kAAAqr0eVQVMyzoj3dq3TYE.png);
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    animation: heartbeat-animation 1.5s ease-in-out infinite;
}
#load-spinner::before { 
    display: none !important; 
}
@keyframes heartbeat-animation {
  0% {
    transform: scale(1); 
    opacity: 0.8;
  }
  50% {
    transform: scale(1.15);
    opacity: 1;           
  }
  100% {
    transform: scale(1);
    opacity: 0.8;
  }
}

  /* 折叠面板图标 */
.inline-drawer-icon {
  -webkit-appearance: none;
  appearance: none;
  width: 20px; 
  height: 20px; 
  background-image: url(https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEF8H9pDzWzbxvOnhQeYdOcb-2IlqwM4QACsUAAAqr0eVR5FkADXYnzMTYE.png);
  background-size: contain;
  background-repeat: no-repeat;
  cursor: pointer;
  box-shadow: none !important;  
  filter: none !important; 
  top: 5px; 
}
.inline-drawer-icon::before {
  display: none; 
}

/* 主页/欢迎面板背景色 */
#chat {
    background-color: #FFF !important; 
}

/* --- 适配优化 --- */
@media (max-width: 360px) { 
    #options_button, #extensionsMenuButton {
        width: 32px !important;
        height: 32px !important;
    }
    #send_but {
        width: 40px !important;
        height: 40px !important;
    }    
}
